function getCreatorCatalogAutoSyncIntervalConfig() {
  const maxIntervalMinutes = Math.max(
    1,
    Math.min(360, Math.floor(CREATOR_CATALOG_CACHE_TTL_SECONDS / 4 / 60)),
  );
  const configuredRaw = String(process.env.CREATOR_CATALOG_AUTO_SYNC_INTERVAL_MINUTES || '').trim();
  const configuredMinutes = configuredRaw ? parsePositiveInt(configuredRaw, null, { min: 1, max: 24 * 60 }) : null;
  if (configuredMinutes == null) {
    return {
      intervalMinutes: maxIntervalMinutes,
      maxIntervalMinutes,
      configuredMinutes: null,
      clamped: false,
    };
  }
  const intervalMinutes = Math.min(configuredMinutes, maxIntervalMinutes);
  return {
    intervalMinutes,
    maxIntervalMinutes,
    configuredMinutes,
    clamped: configuredMinutes > maxIntervalMinutes,
  };
}

function getCreatorCatalogAutoSyncLimitConfig() {
  const raw = String(process.env.CREATOR_CATALOG_AUTO_SYNC_LIMIT || '').trim();
  const parsed = raw ? Number(raw) : null;
  const configured =
    raw && Number.isFinite(parsed) && parsed > 0 ? Math.trunc(parsed) : null;
  const MIN_LIMIT = 500;
  const MAX_LIMIT = 5000;
  if (configured == null) {
    return {
      limitConfigured: null,
      limitEffective: MAX_LIMIT,
      limitFallbackApplied: true,
      limitRaisedToMin: false,
      limitClampedToMax: false,
    };
  }
  let effective = configured;
  let raisedToMin = false;
  let clampedToMax = false;
  if (effective < MIN_LIMIT) {
    effective = MIN_LIMIT;
    raisedToMin = true;
  }
  if (effective > MAX_LIMIT) {
    effective = MAX_LIMIT;
    clampedToMax = true;
  }
  return {
    limitConfigured: configured,
    limitEffective: effective,
    limitFallbackApplied: false,
    limitRaisedToMin: raisedToMin,
    limitClampedToMax: clampedToMax,
  };
}

// Upstream request timeouts.
