if (require.main === module) {
  (async () => {
    if (AURORA_ROUTES_FAIL_CLOSED && !auroraRoutesReady) {
      logger.error(
        {
          aurora_routes_ready: false,
          aurora_routes_fail_closed: AURORA_ROUTES_FAIL_CLOSED,
          aurora_routes_error: auroraRoutesLoadError,
        },
        'Aurora routes unavailable at startup; fail-closed is enabled',
      );
      throw new Error(`AURORA_ROUTES_UNAVAILABLE: ${auroraRoutesLoadError || 'unknown_error'}`);
    }

    const hasDb = Boolean(process.env.DATABASE_URL);
    const autoMigrateDisabled = String(process.env.DB_AUTO_MIGRATE || '').toLowerCase() === 'false';
    const env = String(process.env.NODE_ENV || '').toLowerCase();
    const shouldAutoMigrate = hasDb && !autoMigrateDisabled && env !== 'test';

    if (shouldAutoMigrate) {
      logger.info('Running DB migrations (auto)');
      await runMigrations();
      logger.info('DB migrations complete');
    }

    const server = app.listen(PORT, () => {
      const auroraChatContract = resolveAuroraChatContractConfig();
      logger.info(
        {
          port: PORT,
          use_mock: USE_MOCK,
          mode: API_MODE,
          aurora_chat_response_format: auroraChatContract.response_format,
          aurora_analysis_card_contract_mode: auroraChatContract.analysis_card_contract_mode,
        },
        `Pivota Agent gateway listening on http://localhost:${PORT}, proxying to ${PIVOTA_API_BASE}`,
      );


      // Gemini gate startup check
      try {
        const gate = getGeminiGlobalGate();
        const snap = gate.snapshot();
        if (snap.gate.keyCount === 0) {
          logger.error({ gate: snap.gate }, 'STARTUP: No Gemini API keys found in env. All LLM calls will fail.');
        } else {
          logger.info(
            { keyCount: snap.gate.keyCount, concurrencyMax: snap.gate.concurrencyMax, ratePerMin: snap.gate.ratePerMin },
            'Gemini global gate initialized',
          );
        }
      } catch (err) {
        logger.warn({ err: err.message }, 'Failed to initialize Gemini global gate on startup');
      }
      const autoSyncIntervalConfig = getCreatorCatalogAutoSyncIntervalConfig();
      const intervalMin = autoSyncIntervalConfig.intervalMinutes;
      const initialDelayMs = Math.max(
        Number(process.env.CREATOR_CATALOG_AUTO_SYNC_INITIAL_DELAY_MS || 15000) || 15000,
        0,
      );
      if (CREATOR_CATALOG_AUTO_SYNC_ENABLED) {
        if (autoSyncIntervalConfig.clamped) {
          logger.warn(
            {
              configured_interval_minutes: autoSyncIntervalConfig.configuredMinutes,
              effective_interval_minutes: autoSyncIntervalConfig.intervalMinutes,
              max_allowed_interval_minutes: autoSyncIntervalConfig.maxIntervalMinutes,
              cache_ttl_seconds: CREATOR_CATALOG_CACHE_TTL_SECONDS,
            },
            'CREATOR_CATALOG_AUTO_SYNC_INTERVAL_MINUTES exceeds ttl guardrail; clamping to safe interval',
          );
        }
        setTimeout(() => {
          runCreatorCatalogAutoSync();
          setInterval(runCreatorCatalogAutoSync, intervalMin * 60 * 1000);
        }, initialDelayMs);
      }

      if (PDP_CORE_PREWARM_ENABLED) {
        if (!PDP_CORE_PREWARM_TARGETS.length) {
          logger.warn(
            { env: 'PDP_CORE_PREWARM_TARGETS', enabled: true },
            'PDP core prewarm is enabled but no targets were configured',
          );
        } else {
          setTimeout(() => {
            runPdpCorePrewarmPass().catch((err) => {
              logger.warn({ err: err?.message || String(err) }, 'PDP core prewarm pass failed');
            });
            setInterval(() => {
              runPdpCorePrewarmPass().catch((err) => {
                logger.warn({ err: err?.message || String(err) }, 'PDP core prewarm pass failed');
              });
            }, PDP_CORE_PREWARM_INTERVAL_MS);
          }, PDP_CORE_PREWARM_INITIAL_DELAY_MS);
        }
      }
    });

    server.on('error', (err) => {
      logger.error({ err: err?.message || String(err), port: PORT }, 'Gateway failed to bind');
    });
  })().catch((err) => {
    logger.error({ err: err?.message || String(err) }, 'Startup failed');
    process.exit(1);
  });
}

function deriveTaskBaseFromGatewayUrl(gatewayUrl) {
  // Expect URLs like: http://host/agent/shop/v1/invoke
  return gatewayUrl.replace(/\/invoke\/?$/, '');
}

async function pollCreatorTaskUntilComplete(taskId, baseUrl) {
  const statusUrl = `${baseUrl}/creator/tasks/${taskId}`;
  for (let attempt = 0; attempt < MAX_TASK_POLL_ATTEMPTS; attempt += 1) {
    await new Promise((resolve) => setTimeout(resolve, TASK_POLL_INTERVAL_MS));
    const res = await axios.get(statusUrl, {
      headers: { 'Content-Type': 'application/json' },
      timeout: 15000,
    });
    const body = res.data || {};
    const status = body.status;
    if (status === 'succeeded' && body.result) {
      return body.result;
    }
    if (['failed', 'cancelled', 'timeout', 'expired'].includes(status)) {
      const errMsg = body.error || `Creator task ended with status=${status}`;
      throw new Error(errMsg);
    }
  }
  throw new Error('Creator task did not complete within polling budget');
}

async function callPivotaToolViaGateway(args) {
  const res = await axios.post(UI_GATEWAY_URL, args, {
    headers: { 'Content-Type': 'application/json' },
    timeout: 15000,
  });
  const data = res.data;

  // Handle async/pending responses from the Python gateway when enabled.
  if (data && data.status === 'pending' && data.task_id) {
    const base = deriveTaskBaseFromGatewayUrl(UI_GATEWAY_URL);
    logger.info({ taskId: data.task_id, base }, 'Received pending tool result, polling creator task status');
    return pollCreatorTaskUntilComplete(data.task_id, base);
  }

  return data;
}

const UI_CHAT_SCENARIO_OPTIONS = [
  {
    key: 'commute',
    zh: '通勤/上班',
    en: 'commute/work',
    aliases: ['通勤', '上班', 'commute', 'work'],
  },
  {
    key: 'date',
    zh: '约会',
    en: 'date night',
    aliases: ['约会', 'date', 'date night', 'datenight'],
  },
  {
    key: 'travel',
    zh: '出差/旅行',
    en: 'business trip/travel',
    aliases: ['出差', '旅行', 'travel', 'business trip', 'trip'],
  },
  {
    key: 'outdoor',
    zh: '户外/徒步',
    en: 'hiking/outdoor',
    aliases: ['户外', '徒步', '登山', 'hiking', 'outdoor', 'trekking'],
  },
];

const UI_CHAT_SHOPPING_INTENT_RE =
  /(推荐|商品|买|购买|清单|套装|口红|粉底|化妆|刷|护肤|品牌|预算|travel|hiking|leash|products?|recommend|buy|shopping|gift|skincare|makeup)/i;

const UI_CHAT_SCENARIO_CLARIFY_REASON_CODES = new Set([
  'CLARIFY_SCENARIO',
  'CLARIFY_AMBIGUOUS_QUERY',
]);

function uiChatNormalizeText(input) {
  return String(input || '')
    .toLowerCase()
    .replace(/[\s\p{P}\p{S}]+/gu, '')
    .trim();
}

function uiChatExtractText(message) {
  if (!message) return '';
  if (typeof message.content === 'string') return message.content;
  if (Array.isArray(message.content)) {
    return message.content
      .map((item) => (item && typeof item === 'object' ? item.text : ''))
      .filter(Boolean)
      .join(' ')
      .trim();
  }
  return '';
}

function uiChatParseScenarioSelection(text) {
  const normalized = uiChatNormalizeText(text);
  if (!normalized) return null;
  for (const option of UI_CHAT_SCENARIO_OPTIONS) {
    for (const alias of option.aliases) {
      const aliasNorm = uiChatNormalizeText(alias);
      if (!aliasNorm) continue;
      if (normalized === aliasNorm || normalized.includes(aliasNorm)) {
        return option;
      }
    }
  }
  return null;
}

function uiChatFindLatestScenarioSelection(messages) {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];
    if (message?.role !== 'user') continue;
    const text = uiChatExtractText(message);
    const option = uiChatParseScenarioSelection(text);
    if (option) return { option, index, text };
  }
  return null;
}

function uiChatFindLatestShoppingIntent(messages) {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];
    if (message?.role !== 'user') continue;
    const text = uiChatExtractText(message);
    if (!text || !UI_CHAT_SHOPPING_INTENT_RE.test(text)) continue;
    const scenarioSelection = uiChatParseScenarioSelection(text);
    if (scenarioSelection && uiChatNormalizeText(text).length <= 8) continue;
    return { text, index };
  }
  return null;
}

function uiChatGetFindProductsQuery(args) {
  return String(args?.payload?.search?.query || '').trim();
}

function uiChatIsFindProductsMultiOperation(args) {
  return String(args?.operation || '').trim() === 'find_products_multi';
}

function uiChatGetFinalDecision(result) {
  const traceDecision = result?.metadata?.search_trace?.final_decision;
  if (typeof traceDecision === 'string' && traceDecision.trim()) return traceDecision.trim();
  const decision = result?.metadata?.search_decision?.final_decision;
  if (typeof decision === 'string' && decision.trim()) return decision.trim();
  return '';
}

function uiChatGetClarificationReason(result) {
  const reason = result?.clarification?.reason_code;
  if (typeof reason === 'string' && reason.trim()) return reason.trim();
  const reasonCodes = result?.metadata?.search_trace?.reason_codes;
  if (Array.isArray(reasonCodes)) {
    const hit = reasonCodes.find((code) => UI_CHAT_SCENARIO_CLARIFY_REASON_CODES.has(String(code || '')));
    if (hit) return String(hit);
  }
  return '';
}

function uiChatIsScenarioClarification(result) {
  const finalDecision = uiChatGetFinalDecision(result);
  if (finalDecision !== 'clarify') return false;
  const reason = uiChatGetClarificationReason(result);
  if (UI_CHAT_SCENARIO_CLARIFY_REASON_CODES.has(reason)) return true;
  const question = String(result?.clarification?.question || '').trim();
  if (!question) return false;
  return /场景|scenario|prioritize|哪一类|which/i.test(question);
}

function uiChatBuildLoopBreakQuery({ shoppingText, scenarioOption }) {
  if (!shoppingText || !scenarioOption) return '';
  const base = String(shoppingText || '').trim();
  if (!base) return '';
  const hasZh = /[\u4e00-\u9fff]/.test(base);
  const suffix = hasZh ? ` 使用场景：${scenarioOption.zh}` : ` scenario: ${scenarioOption.en}`;
  const normalizedBase = uiChatNormalizeText(base);
  const normalizedScenarioZh = uiChatNormalizeText(scenarioOption.zh);
  const normalizedScenarioEn = uiChatNormalizeText(scenarioOption.en);
  if (normalizedBase.includes(normalizedScenarioZh) || normalizedBase.includes(normalizedScenarioEn)) {
    return base;
  }
  return `${base}${suffix}`.trim();
}

function uiChatBuildLoopBreakRetryArgs(args, messages, toolResult) {
  if (!uiChatIsFindProductsMultiOperation(args)) return null;
  if (!uiChatIsScenarioClarification(toolResult)) return null;
  const scenarioSelection = uiChatFindLatestScenarioSelection(messages);
  if (!scenarioSelection) return null;
  const shoppingIntent = uiChatFindLatestShoppingIntent(messages);
  if (!shoppingIntent) return null;
  const currentQuery = uiChatGetFindProductsQuery(args);
  const nextQuery = uiChatBuildLoopBreakQuery({
    shoppingText: shoppingIntent.text,
    scenarioOption: scenarioSelection.option,
  });
  if (!nextQuery) return null;
  if (uiChatNormalizeText(nextQuery) === uiChatNormalizeText(currentQuery)) return null;
  const nextArgs = JSON.parse(JSON.stringify(args || {}));
  if (!nextArgs.payload || typeof nextArgs.payload !== 'object') nextArgs.payload = {};
  if (!nextArgs.payload.search || typeof nextArgs.payload.search !== 'object') nextArgs.payload.search = {};
  nextArgs.payload.search.query = nextQuery;
  nextArgs.metadata = {
    ...(nextArgs.metadata && typeof nextArgs.metadata === 'object' ? nextArgs.metadata : {}),
    ui_chat_loop_break: 'scenario_selection_retry',
    ui_chat_loop_break_scenario: scenarioSelection.option.key,
  };
  return {
    nextArgs,
    nextQuery,
    scenario: scenarioSelection.option.key,
    baseQuery: shoppingIntent.text,
  };
}

function uiChatShouldUseRetryResult(initialResult, retryResult) {
  if (!retryResult || typeof retryResult !== 'object') return false;
  if (Array.isArray(retryResult.products) && retryResult.products.length > 0) return true;
  const initialDecision = uiChatGetFinalDecision(initialResult);
  const retryDecision = uiChatGetFinalDecision(retryResult);
  if (retryDecision && retryDecision !== initialDecision) return true;
  return false;
}

async function runAgentWithTools(messages) {
  // messages already contain system message
  const { client: llmClient, model: llmModel } = getUiChatLlmClient();
  const startTs = Date.now();
  let steps = 0;
  let totalToolCalls = 0;
  const recentToolCalls = [];

  function withinRuntimeBudget() {
    if (!MAX_TOTAL_RUNTIME_MS || MAX_TOTAL_RUNTIME_MS <= 0) return true;
    return Date.now() - startTs < MAX_TOTAL_RUNTIME_MS;
  }

  function clampContext() {
    if (!MAX_CONTEXT_MESSAGES || MAX_CONTEXT_MESSAGES <= 0) return;
    if (!Array.isArray(messages)) return;
    if (messages.length <= MAX_CONTEXT_MESSAGES) return;

    // Keep system message(s) and the most recent messages.
    const systemMessages = messages.filter((m) => m.role === 'system');
    const nonSystem = messages.filter((m) => m.role !== 'system');
    const keepNonSystem = nonSystem.slice(-Math.max(MAX_CONTEXT_MESSAGES - systemMessages.length, 0));
    messages.length = 0;
    messages.push(...systemMessages, ...keepNonSystem);
  }

  function budgetExceededMessage(reason) {
    return {
      role: 'assistant',
      content:
        reason === 'runtime'
          ? 'I used up my safety time budget trying to complete this request. Please try again with a shorter or more specific question.'
          : 'I hit an internal safety limit while trying to complete this request. Please rephrase or narrow down what you need.',
    };
  }

  while (true) {
    if (!withinRuntimeBudget()) {
      logger.warn({ steps, totalToolCalls }, 'Agent runtime budget exceeded');
      return budgetExceededMessage('runtime');
    }
    if (MAX_AGENT_STEPS_PER_TURN > 0 && steps >= MAX_AGENT_STEPS_PER_TURN) {
      logger.warn({ steps, totalToolCalls }, 'Agent step budget exceeded');
      return budgetExceededMessage('steps');
    }

    const completion = await llmClient.chat.completions.create({
      model: llmModel,
      messages,
      tools: [
        {
          type: 'function',
          function: uiChatToolSchema,
        },
      ],
      tool_choice: 'auto',
    });

    const msg = completion.choices[0].message;
    steps += 1;

    if (msg.tool_calls && msg.tool_calls.length > 0) {
      if (MAX_TOOL_CALLS_PER_TURN > 0 && totalToolCalls + msg.tool_calls.length > MAX_TOOL_CALLS_PER_TURN) {
        logger.warn(
          { totalToolCalls, requestedCalls: msg.tool_calls.length },
          'Tool call budget exceeded in this turn'
        );
        return budgetExceededMessage('tools');
      }

      for (const toolCall of msg.tool_calls) {
        if (toolCall.type !== 'function') continue;
        const { name, arguments: argStr } = toolCall.function;
        if (name !== 'pivota_shopping_tool') continue;

        let args;
        try {
          args = JSON.parse(argStr || '{}');
        } catch (e) {
          logger.error({ err: e, argStr }, 'Failed to parse tool args');
          throw e;
        }

        logger.info({ tool: name, args }, 'Calling Pivota tool via gateway');

         // Loop detection: same tool + args repeated too many times.
         const toolKey = JSON.stringify({ name, args });
         recentToolCalls.push(toolKey);
         if (recentToolCalls.length > 16) {
           recentToolCalls.shift();
         }
         const duplicates = recentToolCalls.filter((k) => k === toolKey).length;
         if (MAX_TOOL_LOOP_DUPLICATES > 0 && duplicates >= MAX_TOOL_LOOP_DUPLICATES) {
           logger.warn(
             { name, duplicates },
             'Detected potential tool loop (same tool+args repeated)'
           );
           return {
             role: 'assistant',
             content:
               'I seem to be calling the same shopping operation repeatedly without making progress. ' +
               'Please adjust your request or try a different query.',
           };
         }

        let toolResult = await callPivotaToolViaGateway(args);

        const loopBreakRetry = uiChatBuildLoopBreakRetryArgs(args, messages, toolResult);
        if (loopBreakRetry) {
          logger.info(
            {
              scenario: loopBreakRetry.scenario,
              baseQuery: loopBreakRetry.baseQuery,
              nextQuery: loopBreakRetry.nextQuery,
            },
            'Applying UI chat clarify loop-break retry'
          );
          try {
            const retried = await callPivotaToolViaGateway(loopBreakRetry.nextArgs);
            if (uiChatShouldUseRetryResult(toolResult, retried)) {
              toolResult = retried;
              if (toolResult && typeof toolResult === 'object') {
                toolResult.metadata = {
                  ...(toolResult.metadata && typeof toolResult.metadata === 'object'
                    ? toolResult.metadata
                    : {}),
                  ui_chat_loop_break: {
                    applied: true,
                    scenario: loopBreakRetry.scenario,
                    base_query: loopBreakRetry.baseQuery,
                    enriched_query: loopBreakRetry.nextQuery,
                  },
                };
              }
            }
          } catch (retryError) {
            logger.warn(
              {
                err: retryError?.message || String(retryError),
                scenario: loopBreakRetry.scenario,
                nextQuery: loopBreakRetry.nextQuery,
              },
              'UI chat clarify loop-break retry failed'
            );
          }
        }

        messages.push(msg);
        let content = JSON.stringify(toolResult);
        if (MAX_TOOL_CONTENT_CHARS > 0 && content.length > MAX_TOOL_CONTENT_CHARS) {
          content = content.slice(0, MAX_TOOL_CONTENT_CHARS) + '… [truncated]';
        }
        messages.push({
          role: 'tool',
          tool_call_id: toolCall.id,
          name,
          content,
        });
        totalToolCalls += 1;
        clampContext();
      }
      continue;
    }

    // Detect repeated identical clarification messages.
    const lastAssistant = [...messages].reverse().find((m) => m.role === 'assistant');
    if (lastAssistant && lastAssistant.content && lastAssistant.content === msg.content) {
      logger.warn('Detected repeated identical assistant clarification message');
      return {
        role: 'assistant',
        content:
          'I just repeated myself trying to clarify your request and am not making progress. ' +
          'Please rephrase or provide different details so I can help.',
      };
    }

    return msg;
  }
}

app.post('/ui/chat', async (req, res) => {
  try {
    const clientMessages = req.body.messages;

    if (!Array.isArray(clientMessages)) {
      return res.status(400).json({
        error: 'INVALID_REQUEST',
        message: 'Body must have a messages array',
      });
    }

    const defaultPromptPath = path.join(__dirname, '..', 'prompts', 'shopping_agent_system_prompt_v1_5.txt');
    const promptPath = process.env.PIVOTA_UI_CHAT_SYSTEM_PROMPT_PATH || defaultPromptPath;

    let systemPrompt;
    try {
      systemPrompt = fs.readFileSync(promptPath, 'utf8');
    } catch (err) {
      logger.warn({ err, promptPath }, 'Failed to load system prompt file; using fallback prompt');
      systemPrompt = `
You are the Pivota Shopping Agent.

Core rules:
- Use the \`pivota_shopping_tool\` for any shopping, ordering, payment, order-status, or after-sales task. Do not fabricate product/pricing/order/payment/tracking details.
- Maintain the user’s primary goal across turns; treat follow-ups as refinements unless the user explicitly changes goals.
- If the user message looks like meta instructions or a copied template, do not switch tasks silently: restate the current goal in 1 sentence and ask whether to switch goals or continue refining.
- If the user replies with a tier label (e.g. "A/B/C", "beginner/complete/advanced") or a short constraint, treat it as selecting/refining within the current goal.
- Ask at most 1–2 clarifying questions when needed, then proceed.
- Respond in the same language as the user’s most recent message; if mixed and unclear, ask which language to use.
- Use exactly one language per response; do not mix languages within a single answer.
`.trim();
    }

    const today = new Date().toISOString().slice(0, 10);
    systemPrompt = String(systemPrompt || '').replace(/now=\\d{4}-\\d{2}-\\d{2}/g, `now=${today}`).trim();

    const messages = [
      { role: 'system', content: systemPrompt },
      ...clientMessages,
    ];

    const assistantMsg = await runAgentWithTools(messages);

    res.json({
      assistantMessage: assistantMsg,
    });
  } catch (err) {
    logger.error({ err }, 'Error in /ui/chat');
    res.status(500).json({
      error: 'INTERNAL_ERROR',
      message: 'Failed to run agent',
    });
  }
});
